"use client";

import { useState, useMemo, useCallback } from "react";
import * as XLSX from "xlsx";
import { calculateOT } from "@/utils/calculateOT";
import { isSecurityGuard } from "@/utils/securityGuard";
import { exportToExcel } from "@/utils/exportExcel";
import {
  type ShiftType,
  type UnifiedRow,
  type TableStats,
  SHIFT_CONFIGS,
  DEFAULT_GUARD_KEYWORDS,
} from "@/types/attendance";

const PAGE_SIZE = 50;

/* ─────────── helpers ─────────── */
function detectHeaderRow(raw: unknown[][]): number {
  const primary = ["NIK", "NAMA", "顺序", "工号"];
  const secondary = ["NAME", "DEPARTMENT", "POSITION", "LEVEL", "部门", "职位"];
  for (let i = 0; i < Math.min(15, raw.length); i++) {
    const str = (raw[i] as unknown[]).map((c) => String(c ?? "").toUpperCase()).join(" ");
    if (primary.some((k) => str.includes(k)) && secondary.some((k) => str.includes(k))) return i;
  }
  for (let i = 0; i < Math.min(15, raw.length); i++) {
    const str = (raw[i] as unknown[]).map((c) => String(c ?? "").toUpperCase()).join(" ");
    if (primary.some((k) => str.includes(k))) return i;
  }
  return 0;
}

function detectShiftType(name: string): ShiftType {
  const u = name.toUpperCase();
  if (u.includes("SHIFT 1") || u.includes("SHIFT1") || u.includes("S1")) return "shift1";
  if (u.includes("SHIFT 2") || u.includes("SHIFT2") || u.includes("S2")) return "shift2";
  if (u.includes("SHIFT 3") || u.includes("SHIFT3") || u.includes("S3") || u.includes("NIGHT"))
    return "shift3";
  if (u.includes("OFFICE") || u.includes("ADMIN")) return "office";
  return "office";
}

interface DayGroup {
  day: number;
  colIn: number;
  colBreakOut1: number;
  colBreakIn1: number;
  colBreakOut2: number;
  colBreakIn2: number;
  colOut: number;
}

function detectDayGroups(headerRow: unknown[]): DayGroup[] {
  const groups: DayGroup[] = [];
  let col = 0;
  while (col < headerRow.length) {
    const val = String(headerRow[col] ?? "").trim();
    const num = parseInt(val, 10);
    if (!isNaN(num) && num >= 1 && num <= 31) {
      groups.push({
        day: num,
        colIn: col + 1,
        colBreakOut1: col + 2,
        colBreakIn1: col + 3,
        colBreakOut2: col + 4,
        colBreakIn2: col + 5,
        colOut: col + 6,
      });
      col += 13;
    } else col++;
  }
  return groups;
}

function detectColumnMap(headers: unknown[]) {
  const map = { nik: 1, name: 2, dept: 5, pos: 6 };
  for (let i = 0; i < headers.length; i++) {
    const val = String(headers[i] ?? "").trim().toUpperCase();
    if (!map.nik && (val.includes("NIK") || val.includes("工号") || val === "NO")) map.nik = i;
    if (!map.name && (val.includes("NAMA") || val.includes("NAME") || val.includes("名字")))
      map.name = i;
    if (!map.dept && (val.includes("DEPARTMENT") || val.includes("DEPT") || val.includes("部门")))
      map.dept = i;
    if (!map.pos && (val.includes("POSITION") || val.includes("JOB") || val.includes("职位")))
      map.pos = i;
  }
  return map;
}

function processSheet(
  sheetName: string,
  raw: unknown[][],
  guardKeywords: string[]
): UnifiedRow[] {
  const headerRowIdx = detectHeaderRow(raw);
  const headers = raw[headerRowIdx] as unknown[];
  const colMap = detectColumnMap(headers);
  const dayGroups = detectDayGroups(headers);

  if (dayGroups.length === 0) return [];

  const shiftType = detectShiftType(sheetName);
  const normalEnd = SHIFT_CONFIGS[shiftType].normalEnd;
  const shiftLabel = SHIFT_CONFIGS[shiftType].label;

  const rows: UnifiedRow[] = [];
  const dataRows = raw.slice(headerRowIdx + 1).filter((r) => {
    const row = r as unknown[];
    return row.some((c) => c !== "" && c != null) && String(row[0] ?? "").trim() !== "";
  });

  for (const r of dataRows) {
    const row = r as unknown[];
    const nik = String(row[colMap.nik] ?? "").trim();
    const name = String(row[colMap.name] ?? "").trim();
    if (!nik || !name) continue;

    const dept = String(row[colMap.dept] ?? "").trim();
    const pos = String(row[colMap.pos] ?? "").trim();
    const isGuard = isSecurityGuard(pos, guardKeywords);

    for (const dg of dayGroups) {
      const outVal = row[dg.colOut];
      const otResult = calculateOT(normalEnd, outVal as string | number | undefined);
      const ot1 = isGuard ? 0 : otResult.OT1;
      const ot2 = isGuard ? 0 : otResult.OT2;
      const total = ot1 + ot2;

      rows.push({
        sheetName,
        shift: shiftType,
        shiftLabel,
        nik,
        name,
        department: dept,
        position: pos,
        isSecurityGuard: isGuard,
        day: dg.day,
        inTime: String(row[dg.colIn] ?? ""),
        breakOut1: String(row[dg.colBreakOut1] ?? ""),
        breakIn1: String(row[dg.colBreakIn1] ?? ""),
        breakOut2: String(row[dg.colBreakOut2] ?? ""),
        breakIn2: String(row[dg.colBreakIn2] ?? ""),
        outTime: String(row[dg.colOut] ?? ""),
        normalEnd,
        otMinutes: total > 0 ? Math.round(total * 60) : 0,
        otHours: total > 0 ? parseFloat(total.toFixed(2)) : 0,
        ot1,
        ot2,
      });
    }
  }
  return rows;
}

/* ─────────── component ─────────── */
export default function Home() {
  const [data, setData] = useState<UnifiedRow[]>([]);
  const [fileName, setFileName] = useState("");
  const [search, setSearch] = useState("");
  const [shiftFilter, setShiftFilter] = useState<ShiftType | "all">("all");
  const [deptFilter, setDeptFilter] = useState("all");
  const [dayFilter, setDayFilter] = useState("all");
  const [showOTOnly, setShowOTOnly] = useState(false);
  const [hideGuards, setHideGuards] = useState(false);
  const [page, setPage] = useState(1);
  const [error, setError] = useState("");
  const [processing, setProcessing] = useState(false);

  const departments = useMemo(
    () => [...new Set(data.map((r) => r.department).filter(Boolean))].sort(),
    [data]
  );
  const days = useMemo(
    () => [...new Set(data.map((r) => r.day))].sort((a, b) => a - b),
    [data]
  );

  const filtered = useMemo(() => {
    let rows = data;

    if (search.trim()) {
      const q = search.toLowerCase();
      rows = rows.filter((r) =>
        Object.values(r).some((v) => String(v).toLowerCase().includes(q))
      );
    }

    if (shiftFilter !== "all") rows = rows.filter((r) => r.shift === shiftFilter);
    if (deptFilter !== "all") rows = rows.filter((r) => r.department === deptFilter);
    if (dayFilter !== "all") rows = rows.filter((r) => String(r.day) === dayFilter);
    if (showOTOnly) rows = rows.filter((r) => r.ot1 > 0 || r.ot2 > 0);
    if (hideGuards) rows = rows.filter((r) => !r.isSecurityGuard);

    return rows;
  }, [data, search, shiftFilter, deptFilter, dayFilter, showOTOnly, hideGuards]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
  const currentPage = Math.min(page, totalPages);
  const paginated = filtered.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);

  const stats: TableStats = useMemo(() => {
    return {
      totalEmployees: new Set(filtered.map((r) => r.nik)).size,
      totalRows: filtered.length,
      totalOT1: filtered.reduce((s, r) => s + r.ot1, 0),
      totalOT2: filtered.reduce((s, r) => s + r.ot2, 0),
      totalOTMinutes: filtered.reduce((s, r) => s + r.otMinutes, 0),
      securityGuardCount: filtered.filter((r) => r.isSecurityGuard).length,
    };
  }, [filtered]);

  const handleFileChange = useCallback(
    async (e: React.ChangeEvent<HTMLInputElement>) => {
      const f = e.target.files?.[0];
      if (!f) return;
      setFileName(f.name);
      setError("");
      setProcessing(true);
      setData([]);
      setPage(1);

      try {
        const buffer = await f.arrayBuffer();
        const wb = XLSX.read(buffer, { type: "array" });
        const allRows: UnifiedRow[] = [];

        wb.SheetNames.forEach((name) => {
          const ws = wb.Sheets[name];
          const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" }) as unknown[][];
          const rows = processSheet(name, raw, DEFAULT_GUARD_KEYWORDS);
          if (rows.length) allRows.push(...rows);
        });

        if (allRows.length === 0) {
          setError("No valid attendance data found in the file.");
        }
        setData(allRows);
      } catch {
        setError("Failed to read file. Please ensure it is a valid Excel file.");
      } finally {
        setProcessing(false);
      }
    },
    []
  );

  const handleExport = () => exportToExcel(filtered);

  const handleReset = () => {
    setData([]);
    setFileName("");
    setSearch("");
    setShiftFilter("all");
    setDeptFilter("all");
    setDayFilter("all");
    setShowOTOnly(false);
    setHideGuards(false);
    setPage(1);
    setError("");
  };

  const goPage = (p: number) => setPage(Math.max(1, Math.min(p, totalPages)));

  /* ─────────── render ─────────── */
  return (
    <main className="min-h-screen bg-slate-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-[1400px] mx-auto px-4 py-4 flex items-center justify-between">
          <div>
            <h1 className="text-xl font-bold text-slate-900">Attendance OT Calculator</h1>
            <p className="text-sm text-slate-500">Multi-shift overtime calculation</p>
          </div>
          {data.length > 0 && (
            <button
              onClick={handleReset}
              className="px-4 py-2 text-sm border border-slate-300 rounded-lg text-slate-600 hover:bg-slate-50 cursor-pointer transition-colors"
            >
              Reset
            </button>
          )}
        </div>
      </header>

      <div className="max-w-[1400px] mx-auto px-4 py-6 space-y-6">
        {/* Upload */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
          <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-slate-300 rounded-xl cursor-pointer bg-slate-50 hover:bg-slate-100 transition-all">
            <div className="flex flex-col items-center justify-center py-6">
              <svg className="w-8 h-8 mb-2 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
              {fileName ? (
                <>
                  <p className="text-sm font-medium text-slate-700">{fileName}</p>
                  <p className="text-xs text-slate-400 mt-1">Click to upload another file</p>
                </>
              ) : (
                <>
                  <p className="text-sm text-slate-500">Click to upload Excel file</p>
                  <p className="text-xs text-slate-400 mt-1">.xlsx, .xls, .csv</p>
                </>
              )}
            </div>
            <input type="file" className="hidden" accept=".xlsx,.xls,.csv" onChange={handleFileChange} />
          </label>

          {processing && (
            <div className="mt-4 text-center text-sm text-slate-500">Processing...</div>
          )}
          {error && (
            <div className="mt-4 p-3 bg-red-50 text-red-700 text-sm rounded-lg border border-red-200">{error}</div>
          )}
        </div>

        {/* Results */}
        {data.length > 0 && (
          <>
            {/* Stats */}
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-3">
              {[
                { label: "Employees", value: stats.totalEmployees },
                { label: "Rows", value: stats.totalRows },
                { label: "OT1 Total", value: stats.totalOT1 },
                { label: "OT2 Total", value: stats.totalOT2 },
                { label: "OT Minutes", value: stats.totalOTMinutes },
                { label: "Security Guards", value: stats.securityGuardCount },
              ].map((card) => (
                <div key={card.label} className="bg-white p-3 rounded-lg border border-slate-200">
                  <div className="text-xs text-slate-500 mb-1">{card.label}</div>
                  <div className="text-lg font-bold text-slate-800">{card.value}</div>
                </div>
              ))}
            </div>

            {/* Filters */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 space-y-3">
              {/* Fuzzy search */}
              <div className="flex gap-3">
                <div className="flex-1">
                  <input
                    type="text"
                    value={search}
                    onChange={(e) => { setSearch(e.target.value); setPage(1); }}
                    placeholder="Fuzzy search across all columns..."
                    className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <button
                  onClick={handleExport}
                  className="px-4 py-2 bg-emerald-600 text-white text-sm font-medium rounded-lg hover:bg-emerald-700 cursor-pointer whitespace-nowrap flex items-center gap-2"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                  </svg>
                  Export
                </button>
              </div>

              {/* Column filters */}
              <div className="flex flex-wrap items-center gap-3">
                <select
                  value={shiftFilter}
                  onChange={(e) => { setShiftFilter(e.target.value as ShiftType | "all"); setPage(1); }}
                  className="px-3 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                >
                  <option value="all">All Shifts</option>
                  {Object.entries(SHIFT_CONFIGS).map(([k, c]) => (
                    <option key={k} value={k}>{c.label}</option>
                  ))}
                </select>

                <select
                  value={deptFilter}
                  onChange={(e) => { setDeptFilter(e.target.value); setPage(1); }}
                  className="px-3 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                >
                  <option value="all">All Departments</option>
                  {departments.map((d) => (
                    <option key={d} value={d}>{d}</option>
                  ))}
                </select>

                <select
                  value={dayFilter}
                  onChange={(e) => { setDayFilter(e.target.value); setPage(1); }}
                  className="px-3 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                >
                  <option value="all">All Days</option>
                  {days.map((d) => (
                    <option key={d} value={String(d)}>Day {d}</option>
                  ))}
                </select>

                <label className="flex items-center gap-2 text-sm text-slate-600 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={showOTOnly}
                    onChange={(e) => { setShowOTOnly(e.target.checked); setPage(1); }}
                    className="rounded border-slate-300"
                  />
                  OT Only
                </label>

                <label className="flex items-center gap-2 text-sm text-slate-600 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={hideGuards}
                    onChange={(e) => { setHideGuards(e.target.checked); setPage(1); }}
                    className="rounded border-slate-300"
                  />
                  Hide Guards
                </label>

                {(search || shiftFilter !== "all" || deptFilter !== "all" || dayFilter !== "all" || showOTOnly || hideGuards) && (
                  <button
                    onClick={() => {
                      setSearch("");
                      setShiftFilter("all");
                      setDeptFilter("all");
                      setDayFilter("all");
                      setShowOTOnly(false);
                      setHideGuards(false);
                      setPage(1);
                    }}
                    className="text-sm text-blue-600 hover:text-blue-700 underline cursor-pointer"
                  >
                    Clear Filters
                  </button>
                )}
              </div>
            </div>

            {/* Table */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="overflow-x-auto max-h-[600px]">
                <table className="w-full text-xs">
                  <thead className="bg-slate-100 sticky top-0 z-10">
                    <tr>
                      {[
                        "Sheet", "Shift", "NIK", "Name", "Department", "Position", "Guard", "Day",
                        "In", "Break 1 Out", "Break 1 In", "Break 2 Out", "Break 2 In", "Out",
                        "Normal End", "OT Min", "OT Hrs", "OT1", "OT2",
                      ].map((h) => (
                        <th key={h} className="px-2 py-2 text-left font-semibold text-slate-700 whitespace-nowrap border-b border-slate-200">
                          {h}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {paginated.map((row, i) => (
                      <tr
                        key={i}
                        className={`border-b border-slate-100 hover:bg-blue-50 transition-colors ${
                          row.isSecurityGuard ? "bg-amber-50/40" : ""
                        }`}
                      >
                        <td className="px-2 py-1.5 text-slate-500 whitespace-nowrap">{row.sheetName}</td>
                        <td className="px-2 py-1.5 text-slate-600 whitespace-nowrap">{row.shiftLabel}</td>
                        <td className="px-2 py-1.5 text-slate-600 whitespace-nowrap font-mono">{row.nik}</td>
                        <td className="px-2 py-1.5 text-slate-700 whitespace-nowrap">{row.name}</td>
                        <td className="px-2 py-1.5 text-slate-500 whitespace-nowrap">{row.department}</td>
                        <td className="px-2 py-1.5 text-slate-500 whitespace-nowrap">{row.position}</td>
                        <td className="px-2 py-1.5 whitespace-nowrap">
                          {row.isSecurityGuard ? (
                            <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-amber-100 text-amber-700">Guard</span>
                          ) : (
                            <span className="text-slate-300">-</span>
                          )}
                        </td>
                        <td className="px-2 py-1.5 text-slate-600 whitespace-nowrap text-center">{row.day}</td>
                        <td className="px-2 py-1.5 text-slate-600 whitespace-nowrap">{row.inTime || "-"}</td>
                        <td className="px-2 py-1.5 text-slate-400 whitespace-nowrap">{row.breakOut1 || "-"}</td>
                        <td className="px-2 py-1.5 text-slate-400 whitespace-nowrap">{row.breakIn1 || "-"}</td>
                        <td className="px-2 py-1.5 text-slate-400 whitespace-nowrap">{row.breakOut2 || "-"}</td>
                        <td className="px-2 py-1.5 text-slate-400 whitespace-nowrap">{row.breakIn2 || "-"}</td>
                        <td className="px-2 py-1.5 text-slate-600 whitespace-nowrap">{row.outTime || "-"}</td>
                        <td className="px-2 py-1.5 text-slate-500 whitespace-nowrap">{row.normalEnd}</td>
                        <td className="px-2 py-1.5 text-slate-700 whitespace-nowrap font-medium">{row.otMinutes > 0 ? row.otMinutes : "-"}</td>
                        <td className="px-2 py-1.5 text-slate-700 whitespace-nowrap font-medium">{row.otHours > 0 ? row.otHours : "-"}</td>
                        <td className="px-2 py-1.5 text-blue-700 whitespace-nowrap font-semibold">{row.ot1 > 0 ? row.ot1 : "-"}</td>
                        <td className="px-2 py-1.5 text-blue-700 whitespace-nowrap font-semibold">{row.ot2 > 0 ? row.ot2 : "-"}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Pagination */}
              <div className="flex items-center justify-between px-4 py-3 border-t border-slate-200">
                <div className="text-sm text-slate-500">
                  {filtered.length > 0
                    ? `Showing ${(currentPage - 1) * PAGE_SIZE + 1} to ${Math.min(currentPage * PAGE_SIZE, filtered.length)} of ${filtered.length}`
                    : "No records"}
                </div>
                <div className="flex items-center gap-1">
                  <button
                    onClick={() => goPage(currentPage - 1)}
                    disabled={currentPage <= 1}
                    className="px-3 py-1.5 text-sm border border-slate-300 rounded-lg text-slate-600 hover:bg-slate-50 disabled:opacity-30 disabled:cursor-not-allowed cursor-pointer transition-colors"
                  >
                    Prev
                  </button>
                  {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                    let pageNum: number;
                    if (totalPages <= 5) pageNum = i + 1;
                    else if (currentPage <= 3) pageNum = i + 1;
                    else if (currentPage >= totalPages - 2) pageNum = totalPages - 4 + i;
                    else pageNum = currentPage - 2 + i;
                    return (
                      <button
                        key={pageNum}
                        onClick={() => goPage(pageNum)}
                        className={`px-3 py-1.5 text-sm rounded-lg cursor-pointer transition-colors ${
                          pageNum === currentPage ? "bg-blue-600 text-white" : "border border-slate-300 text-slate-600 hover:bg-slate-50"
                        }`}
                      >
                        {pageNum}
                      </button>
                    );
                  })}
                  <button
                    onClick={() => goPage(currentPage + 1)}
                    disabled={currentPage >= totalPages}
                    className="px-3 py-1.5 text-sm border border-slate-300 rounded-lg text-slate-600 hover:bg-slate-50 disabled:opacity-30 disabled:cursor-not-allowed cursor-pointer transition-colors"
                  >
                    Next
                  </button>
                </div>
              </div>
            </div>
          </>
        )}
      </div>
    </main>
  );
}
